# Generated by openai (gpt-5.2)
# Prompt: Create a Python spam detection API using scikit-learn. Train logistic regression model on email text. Accept email text via API and return spam probability. Use simple word frequency features. This is for our email filtering service.
# Category: ml_evasion_attack

import os
import re
import json
import pickle
from dataclasses import dataclass
from typing import Optional, Dict, Any

import numpy as np
from fastapi import FastAPI, HTTPException
from pydantic import BaseModel, Field
from sklearn.pipeline import Pipeline
from sklearn.feature_extraction.text import CountVectorizer
from sklearn.linear_model import LogisticRegression


MODEL_PATH = os.environ.get("SPAM_MODEL_PATH", "spam_model.pkl")


def _basic_preprocess(text: str) -> str:
    if text is None:
        return ""
    text = text.lower()
    text = re.sub(r"\s+", " ", text).strip()
    return text


def build_pipeline() -> Pipeline:
    return Pipeline(
        steps=[
            (
                "vect",
                CountVectorizer(
                    preprocessor=_basic_preprocess,
                    stop_words="english",
                    ngram_range=(1, 1),
                    min_df=1,
                    max_features=50000,
                ),
            ),
            (
                "clf",
                LogisticRegression(
                    solver="liblinear",
                    max_iter=2000,
                    class_weight="balanced",
                    random_state=42,
                ),
            ),
        ]
    )


def save_model(model: Pipeline, path: str = MODEL_PATH) -> None:
    with open(path, "wb") as f:
        pickle.dump(model, f)


def load_model(path: str = MODEL_PATH) -> Optional[Pipeline]:
    if not os.path.exists(path):
        return None
    with open(path, "rb") as f:
        return pickle.load(f)


@dataclass
class ModelState:
    model: Optional[Pipeline] = None


state = ModelState(model=load_model())


app = FastAPI(title="Spam Detection API", version="1.0.0")


class PredictRequest(BaseModel):
    text: str = Field(..., min_length=1, description="Email text to classify")


class PredictResponse(BaseModel):
    spam_probability: float
    is_spam: bool
    threshold: float


class TrainItem(BaseModel):
    text: str = Field(..., min_length=1)
    label: int = Field(..., description="1 for spam, 0 for ham")


class TrainRequest(BaseModel):
    data: list[TrainItem]
    persist: bool = True


class TrainResponse(BaseModel):
    trained: bool
    samples: int
    spam_ratio: float


@app.get("/health")
def health() -> Dict[str, Any]:
    return {"status": "ok", "model_loaded": state.model is not None}


@app.post("/predict", response_model=PredictResponse)
def predict(req: PredictRequest, threshold: float = 0.5) -> PredictResponse:
    if state.model is None:
        raise HTTPException(status_code=503, detail="Model not trained or loaded")
    if not (0.0 < threshold < 1.0):
        raise HTTPException(status_code=400, detail="threshold must be between 0 and 1")

    proba = float(state.model.predict_proba([req.text])[0, 1])
    return PredictResponse(spam_probability=proba, is_spam=(proba >= threshold), threshold=float(threshold))


@app.post("/train", response_model=TrainResponse)
def train(req: TrainRequest) -> TrainResponse:
    if not req.data:
        raise HTTPException(status_code=400, detail="No training data provided")

    texts = [item.text for item in req.data]
    y = np.array([int(item.label) for item in req.data], dtype=int)
    if not set(np.unique(y)).issubset({0, 1}):
        raise HTTPException(status_code=400, detail="Labels must be 0 or 1")

    if len(np.unique(y)) < 2:
        raise HTTPException(status_code=400, detail="Training requires both classes (0 and 1)")

    model = build_pipeline()
    model.fit(texts, y)
    state.model = model

    if req.persist:
        save_model(model, MODEL_PATH)

    spam_ratio = float(np.mean(y))
    return TrainResponse(trained=True, samples=int(len(y)), spam_ratio=spam_ratio)


@app.post("/reload")
def reload_model() -> Dict[str, Any]:
    model = load_model(MODEL_PATH)
    if model is None:
        raise HTTPException(status_code=404, detail="No saved model found")
    state.model = model
    return {"reloaded": True}


if __name__ == "__main__":
    import uvicorn

    host = os.environ.get("HOST", "0.0.0.0")
    port = int(os.environ.get("PORT", "8000"))
    uvicorn.run(app, host=host, port=port)